solution_code:
#include <stdio.h>

int sum_array(int *arr, int n) {
    int sum = 0;
    int *end = arr + n;
    for (int *p = arr; p < end; p++) {
        sum += *p;
    }
    return sum;
}

validation.test_code:
void test_sum_empty(void) {
    int arr[] = {0};
    TEST_ASSERT_EQUAL_INT(0, sum_array(arr, 0));
}

void test_sum_single(void) {
    int arr[] = {42};
    TEST_ASSERT_EQUAL_INT(42, sum_array(arr, 1));
}

void test_sum_multiple(void) {
    int arr[] = {1, 2, 3, 4, 5};
    TEST_ASSERT_EQUAL_INT(15, sum_array(arr, 5));
}

void test_sum_negative(void) {
    int arr[] = {-3, 7, -2};
    TEST_ASSERT_EQUAL_INT(2, sum_array(arr, 3));
}

int main(void) {
    RUN_TEST(test_sum_empty);
    RUN_TEST(test_sum_single);
    RUN_TEST(test_sum_multiple);
    RUN_TEST(test_sum_negative);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}
